kill_port() {
    local port=$1
    local pid=""
    if command -v lsof > /dev/null 2>&1; then
        pid=$(lsof -ti :$port 2>/dev/null || true)
    elif command -v fuser > /dev/null 2>&1; then
        pid=$(fuser $port/tcp 2>/dev/null || true)
    elif command -v ss > /dev/null 2>&1; then
        pid=$(ss -tlnp "sport = :$port" 2>/dev/null | grep -oP 'pid=\K\d+' | head -1 || true)
    fi
    if [ -n "$pid" ]; then
        echo "  缂傚倸鍊搁崐鎼佸磹閹间礁纾归柣鎴ｅГ閸婂潡鏌ㄩ弴妤€浜鹃柧鑽ゅ仱閻擃偊宕堕妸褉妲堥梺鎼炲妼閸婂潡寮婚悢椋庢殝闁瑰嘲鐭堝鑸电箾?$port 闂傚倸鍊搁崐宄懊归崶褏鏆﹂柣銏㈩焾绾惧鏌ｉ幇顒佹儓缂佲偓閸曨厽鍠愰柣妤€鐗嗙粭鎺旂棯閹岀吋闁哄本鐩鎾Ω閵夈倗鏁栭梻浣告惈濡绮婚幋锔界畳闂備胶绮幐绋棵归悜钘夌闁绘绮悡?(PID: $pid), 闂傚倸鍊搁崐鎼佸磹閹间礁纾归柣鎴ｅГ閸婂潡鏌ㄩ弴姘舵濞存粌缍婇弻娑㈠箛闂堟稒鐏嶉梺鍝勬噺缁诲牓寮婚弴鐔风窞闁糕剝蓱閻濇柨鈹戦埥鍡椾簼闁挎岸妫佹径鎰叆婵犻潧妫欓崳娲偣閹板墎绡€闁?.."
        kill -9 $pid 2>/dev/null || true
        sleep 1
    fi
}

